&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जम्मू-कश्मीर के बारे में जानिए:&lt;/span&gt;&lt;/u&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;राजधानी&lt;/span&gt;: श्रीनगर (ग्रीष्मकालीन), जम्मू (शीतकालीन)।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आधिकारिक भाषा&lt;/span&gt;: उर्दू।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;क्षेत्रीय त्यौहार&lt;/span&gt;:
	&lt;ul&gt;
		&lt;li&gt;हेमिस त्योहार - लद्दाख का एक बौद्ध त्योहार।&lt;/li&gt;
		&lt;li&gt;उर्स को ज़ियारतों के रूप में भी जाना जाता है - एक कश्मीरी मुस्लिम त्योहार।&lt;/li&gt;
		&lt;li&gt;सिंधु (सिंधु) दर्शन, अमरनाथ यात्रा।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कला रूप:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;बसोहली पेंटिंग&lt;/span&gt;, कसीदा कढ़ाई।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संगीत&lt;/span&gt;: सूफियाना कलाम, हाफिज नगमा, लदीशाह, चकरी।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;नृत्य&lt;/span&gt;: कुद, दमहाल, रौफ, भांड पाथेर।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;भौगोलिक संकेत&lt;/span&gt;: कश्मीरी पश्मीना, कश्मीरी सोज़ानी क्राफ्ट, कानी शाल, कश्मीर पेपर माछे, कश्मीरी अखरोट की नक्काशी, खताम्बंद, और कश्मीरी हाथ से बुने कालीन, कश्मीरी केसर।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;Little Rann of Kutch.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Indian Wild Ass Sanctuary&lt;/strong&gt;, sometimes referred to as the &lt;strong&gt;Wild Ass Wildlife Sanctuary&lt;/strong&gt;, is situated in&lt;strong&gt; India&amp;#39;s Gujarat state in the Little Rann of Kutch.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The&lt;strong&gt; Wildlife Protection Act of 1972&lt;/strong&gt; was the&lt;strong&gt; legal basis&lt;/strong&gt; on which the&lt;strong&gt; wildlife sanctuary was created.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The sanctuary is where it is possible to see the&lt;strong&gt; critically endangered Indian Wild Ass (Khur)&lt;/strong&gt; subspecies of the &lt;strong&gt;Asiatic Wild Ass species Onager (Equus hemionus).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The&lt;strong&gt; main threat&lt;/strong&gt; faced by the sanctuary is the&lt;strong&gt; illegal salt&lt;/strong&gt; panning&amp;nbsp;activity in the area.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;25% of India&amp;rsquo;s salt supply &lt;/strong&gt;comes from panning activity in the area.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Sunderbans:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;The Sundarbans is of universal importance for&lt;strong&gt; endangered species&lt;/strong&gt; including the&lt;strong&gt; Royal Bengal Tiger, Ganges and Irawadi dolphins, estuarine crocodiles.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Upper Himalayas:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The Himalayan Range&amp;#39;s tallest mountains are known as the Great Himalayas, Greater Himalayas, or Himadri.&lt;/li&gt;
		&lt;li&gt;The Greater Himalayas mountain range includes&lt;strong&gt; Mount Everest, the highest peak in the world, &lt;/strong&gt;as well as other &amp;quot;nearest highest&amp;quot; peaks like&lt;strong&gt; Kangchenjunga, Lhotse, and Nanga Parbat.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Plains of Ganga:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;Large floodplains of the &lt;strong&gt;Indus, Ganga, and Brahmaputra&lt;/strong&gt; river systems are collectively referred to as the Indus-Ganga plains, commonly referred to as the&lt;strong&gt; &amp;quot;Great Plains.&amp;quot;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;कच्छ का छोटा रण&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारतीय जंगली गधा अभयारण्य&lt;/strong&gt;, जिसे कभी-कभी &lt;strong&gt;जंगली गधा वन्यजीव अभयारण्य&lt;/strong&gt; के रूप में जाना जाता है, &lt;strong&gt;भारत के गुजरात राज्य में कच्छ के छोटे रण में स्थित है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;1972 का वन्यजीव संरक्षण अधिनियम को कानूनी आधार मानकर उसी का अंतर्गत यह&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;वन्यजीव अभयारण्य बनाया गया&lt;/strong&gt; था।&lt;/li&gt;
	&lt;li&gt;अभयारण्य वह स्थान&amp;nbsp;है जहां &lt;strong&gt;एशियाई जंगली गधों की प्रजाति ओनागर (इक्वस हेमियोनस) &lt;/strong&gt;की गंभीर रूप से &lt;strong&gt;लुप्तप्राय&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उप-प्रजाति&lt;/span&gt;&lt;strong&gt;&amp;nbsp;भारतीय जंगली गधों&amp;nbsp;(खुर) &lt;/strong&gt;को देख पाना संभव है।&lt;/li&gt;
	&lt;li&gt;अभयारण्य द्वारा सामना किया जाने वाला &lt;strong&gt;मुख्य खतरा&lt;/strong&gt; क्षेत्र में &lt;strong&gt;अवैध नमक&lt;/strong&gt; अभिनमन गतिविधि है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत की नमक आपूर्ति का 25% &lt;/strong&gt;क्षेत्र में अभिनमन गतिविधि से आता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;सुंदरबन:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;रॉयल बंगाल टाइगर, गंगा और इरावदी डॉल्फ़िन, मुहाना मगरमच्छ सहित लुप्तप्राय प्रजातियों &lt;/strong&gt;के लिए सुंदरवन सार्वभौमिक महत्व का है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;हिमालय का उपरी क्षेत्र:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;हिमालय श्रृंखला के सबसे ऊंचे पहाड़ों को ग्रेटर हिमालय,&amp;nbsp;या हिमाद्री के रूप में जाना जाता है।&lt;/li&gt;
		&lt;li&gt;ग्रेटर हिमालय पर्वत श्रृंखला में &lt;strong&gt;माउंट एवरेस्ट, दुनिया की सबसे ऊंची चोटी&lt;/strong&gt;, साथ ही &lt;strong&gt;कंचनजंगा, ल्होत्से और नंगा पर्वत &lt;/strong&gt;जैसी अन्य &amp;quot;निकटतम सबसे ऊंची&amp;quot; चोटियां शामिल हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गंगा का मैदान:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;सिंधु, गंगा और ब्रह्मपुत्र &lt;/strong&gt;नदी तंत्र&amp;nbsp;के विशाल&amp;nbsp;बाढ़ के मैदानों को सामूहिक रूप से सिंधु-गंगा के मैदानों के रूप में जाना जाता है, जिन्हें आमतौर पर &lt;strong&gt;&amp;quot;विशाल&amp;nbsp;मैदान&amp;quot;&lt;/strong&gt; कहा जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

questions.statement:
&lt;p&gt;Which is/are NOT Abiotic components?&lt;/p&gt;

&lt;p&gt;I. Plants&lt;/p&gt;

&lt;p&gt;II. Animals&lt;/p&gt;
III. Water<br>&lt;p&gt;कौन सा अजैविक घटक नहीं हैं?&lt;/p&gt;

&lt;p&gt;I. पौधे&lt;/p&gt;

&lt;p&gt;II. पशु&lt;/p&gt;

&lt;p&gt;III. &amp;nbsp;जल&lt;/p&gt;

questions.explanation:
&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;An abiotic component is a non-living component in the environment.&lt;/li&gt;
	&lt;li&gt;&amp;nbsp;These components have a major influence on a living organism.&lt;/li&gt;
	&lt;li&gt;&amp;nbsp;Abiotic components are water, sunlight, temperature, fire, heat, sunlight, oxygen, climate.&lt;/li&gt;
	&lt;li&gt;&amp;nbsp; Water is an only abiotic component from the above-mentioned components.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;एक अजैविक घटक पर्यावरण में एक निर्जीव घटक है।&lt;/li&gt;
	&lt;li&gt;इन घटकों का एक जीवित जीव पर बड़ा प्रभाव होता है।&lt;/li&gt;
	&lt;li&gt;अजैविक घटक जल, सूर्य का प्रकाश, तापमान, अग्नि, ऊष्मा, सूर्य का प्रकाश, ऑक्सीजन, जलवायु हैं।&lt;/li&gt;
	&lt;li&gt;उपर्युक्त घटकों में से केवल जल एक अजैविक घटक है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Rajasthan&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Keoladeo National Park is located in the Bharatpur district of Rajasthan&lt;/span&gt;&lt;/u&gt;.&lt;/li&gt;
	&lt;li&gt;It is formerly known as the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bharatpur Bird Sanctuary&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;This site was declared a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;UNESCO World Heritage Site in 1985&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;It became a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;bird sanctuary in 1956&lt;/span&gt;&amp;nbsp;and was declared a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;national park in 1981&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;It was&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;renamed Keoladeo for the ancient temple&amp;nbsp;&lt;/span&gt;in the park dedicated to the Hindu god Shiva.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Parks of Rajasthan:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color:  (33, 37, 41); width: 300px;&quot;&gt;
	&lt;thead&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;SL. No.&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;Name of the National Parks&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;District&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;Year of Notification&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;Area(Sq.km.)&lt;/th&gt;
		&lt;/tr&gt;
	&lt;/thead&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Mukundra Hills (Darrah) National Park&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Kota, Chittorgarh&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;2006&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;200.54&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;2.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Keoladeo Ghana National Park&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Bharatpur&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1981&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;28.73&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;3.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Ranthambhore National Park&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Sawai Madhopur&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1980&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;282&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;राजस्थान&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:20px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color:  (33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;केवलादेव राष्ट्रीय उद्यान राजस्थान के भरतपुर जिले में स्थित है&lt;/span&gt;&lt;/u&gt;।&lt;/li&gt;
	&lt;li&gt;इसे पहले &lt;span style=&quot;font-weight: bolder;&quot;&gt;भरतपुर पक्षी अभयारण्य&lt;/span&gt; के नाम से जाना जाता था।&lt;/li&gt;
	&lt;li&gt;इस स्थल को &lt;span style=&quot;font-weight: bolder;&quot;&gt;1985 में यूनेस्को विश्व धरोहर स्थल&lt;/span&gt; घोषित किया गया था।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;1956 में इसे पक्षी अभयारण्य&lt;/span&gt; बना दिया गया और &lt;span style=&quot;font-weight: bolder;&quot;&gt;1981 में इसे राष्ट्रीय उद्यान&lt;/span&gt; घोषित कर दिया गया।&lt;/li&gt;
	&lt;li&gt;पार्क में स्थित हिंदू भगवान शिव को समर्पित &lt;span style=&quot;font-weight: bolder;&quot;&gt;प्राचीन मंदिर के कारण इसका नाम बदलकर केवलादेव रखा गया&lt;/span&gt; ।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:20px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; style=&quot;color:  (33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;राजस्थान के राष्ट्रीय उद्यान:&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color:  (33, 37, 41); width: 300px;&quot;&gt;
	&lt;thead&gt;
		&lt;tr&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;क्रम सं.&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;राष्ट्रीय उद्यानों का नाम&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;ज़िला&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;अधिसूचना का वर्ष&lt;/th&gt;
			&lt;th scope=&quot;col&quot; style=&quot;text-align: center;&quot;&gt;क्षेत्र (वर्ग किमी.)&lt;/th&gt;
		&lt;/tr&gt;
	&lt;/thead&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मुकुंदरा हिल्स (दर्रा) राष्ट्रीय उद्यान&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कोटा, चित्तौड़गढ़&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;2006&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;200.54&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;2.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;केवलादेव घाना राष्ट्रीय उद्यान&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;भरतपुर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1981&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;28.73&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;3.&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;रणथंभौर राष्ट्रीय उद्यान&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;सवाई माधोपुर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;1980&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;282&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&lt;u&gt;&lt;strong&gt;&amp;nbsp;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(88, 89, 91); --darkreader-inline-color:#8f8573;&quot;&gt;Sundarbans National Park - Odisha.&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(88, 89, 91); --darkreader-inline-color:#8f8573;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(88, 89, 91); --darkreader-inline-color:#8f8573;&quot;&gt;&lt;strong&gt;Sundarbans National Park - Odisha&lt;/strong&gt;, this&lt;/span&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;&amp;nbsp;land results from the &lt;strong&gt;strong tide that is a daily reality in Sunderban.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;Sunderban is&amp;nbsp;&lt;/span&gt;&lt;b data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;located in the North and South 24 Pargana Districts of the Indian State of West Bengal&lt;/b&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;&lt;strong&gt;Sunderban Biosphere Reserve &lt;/strong&gt;at a&lt;strong&gt; total of 9630 sq km&lt;/strong&gt;, is the&lt;strong&gt; third largest such reserve in India having got this status in 1989.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;It is &lt;strong&gt;part of the Sundarbans on the Ganges Delta and adjacent to the Sundarban Reserve Forest in Bangladesh. &lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(32, 33, 36); --darkreader-inline-color:#bbb2a1;&quot;&gt;&lt;strong&gt;It is located in southwest Bangladesh.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color:#968b7a;&quot;&gt;&lt;strong&gt;Manas National Park&lt;/strong&gt; is a national park,&lt;strong&gt; Project Tiger reserve, biosphere reserve, and elephant reserve in Assam, India.&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color:#968b7a;&quot;&gt;&lt;strong&gt;Bandhavgarh National Park&lt;/strong&gt; is in the&lt;strong&gt; central Indian state of Madhya Pradesh&lt;/strong&gt;. This biodiverse park is known for its&lt;strong&gt; big&amp;nbsp;population of royal Bengal tigers, mainly&amp;nbsp;in the central Tala zone.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color:#968b7a;&quot;&gt;&lt;strong&gt;Jim Corbett National Park is a forested wildlife sanctuary in northern India&amp;rsquo;s Uttarakhand State.&lt;/strong&gt; &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(77, 81, 86); --darkreader-inline-color:#968b7a;&quot;&gt;Rich in flowers&amp;nbsp;and animals, it&amp;rsquo;s known for its Bengal tigers.&lt;strong&gt; Animals, as well as&amp;nbsp;tigers, leopards and wild elephants, roam the Dhikala zone.&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;&quot;&gt;सही उत्तर&lt;strong&gt; &lt;u&gt;सुंदरबन राष्ट्रीय उद्यान - ओडिशा&lt;/u&gt;&lt;/strong&gt;&lt;u&gt; &lt;/u&gt;है।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;सुंदरबन राष्ट्रीय उद्यान - ओडिशा&lt;/strong&gt;, यह भूमि&lt;strong&gt; &lt;/strong&gt;&lt;strong&gt;शक्तिशाली&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;ज्वार&lt;/strong&gt;&amp;nbsp;का&amp;nbsp;परिणाम है &lt;strong&gt;जो कि सुंदरबन में प्रतिदिन घटित होती&amp;nbsp;&lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;सुंदरबन &lt;strong&gt;भारतीय राज्य पश्चिम बंगाल के उत्तर और दक्षिण 24 परगना जिलों में स्थित &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कुल 9630 वर्ग किमी में फैला सुंदरबन बायोस्फीयर रिजर्व, भारत में तीसरा सबसे बड़ा ऐसा रिजर्व &lt;/strong&gt;है जिसे&lt;strong&gt;&amp;nbsp;वर्ष 1989 में यह दर्जा मिला था।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह&lt;strong&gt; गंगा डेल्टा पर सुंदरबन का हिस्सा है और बांग्लादेश में स्थित सुंदरबन रिजर्व फॉरेस्ट से सटा हुआ है&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह दक्षिण पश्चिम बांग्लादेश में स्थित &lt;/strong&gt;है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;मानस राष्ट्रीय उद्यान&lt;/strong&gt; &lt;strong&gt;असम&lt;/strong&gt;, &lt;strong&gt;भारत में स्थित&amp;nbsp;&lt;/strong&gt;एक राष्ट्रीय उद्यान&lt;strong&gt;, प्रोजेक्ट टाइगर रिजर्व, बायोस्फीयर रिजर्व और हाथी रिजर्व &lt;/strong&gt;है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;बांधवगढ़ राष्ट्रीय उद्यान&lt;/strong&gt; &lt;strong&gt;मध्य भारतीय राज्य मध्य प्रदेश&lt;/strong&gt; में स्थित है। यह जैव विविधता उद्यान मुख्य रूप से &lt;strong&gt;मध्य ताल क्षेत्र में रॉयल बंगाल टाईगर्स&amp;nbsp;की बड़ी आबादी के लिए जाना जाता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जिम कॉर्बेट राष्ट्रीय उद्यान उत्तरी भारत के उत्तराखंड राज्य में स्थितएक वनाच्छादित वन्यजीव अभयारण्य &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;फूलों और जानवरों से भरपूर, यह अपने बंगाल टाइगर्स के लिए जाना जाता है। यहाँ स्थित&amp;nbsp;&lt;strong&gt;ढिकाला क्षेत्र में जानवरों के साथ-साथ बाघ, तेंदुए और जंगली हाथी घूमते हैं।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;West Bengal&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Buxa Tiger Reserve is located in West Bengal.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Buxa Tiger Reserve was &lt;strong&gt;established in 1983&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;It was&amp;nbsp;the then &lt;strong&gt;15&lt;sup&gt;th&lt;/sup&gt;&amp;nbsp;tiger reserve in India.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Animals&amp;nbsp;found in Buxa Tiger Reserve Indian leopard, Bengal tiger, clouded leopard, giant squirrel, gaur, chital, and wild boar.&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;National Park/Wildlife sanctuary in West Bengal are&lt;strong&gt; West Sunderban Wildlife Sanctuary, Gorumara National Park, Neora Valley National Park, Singalila National Park, Sunderban National Park (STR) Tiger Reserve, and Jaldapara National Park.&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;State&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;National Park/Wildlife sanctuary&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Jharkhand&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Singhbhum Elephant Reserve,&amp;nbsp;Betla National Park,&amp;nbsp;Dalma Wildlife Sanctuary, Hazaribagh Wildlife Sanctuary&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Chhattisgarh&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Achanakmar Wildlife Sanctuary,&amp;nbsp;Indravati Tiger Reserve,&amp;nbsp;Pamed Wild Buffalo Wildlife Sanctuary,&amp;nbsp;Kanger Valley National Park,&amp;nbsp;Guru Ghasi Das (Sanjay) National Park&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Bihar&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Valmiki Tiger Reserve,&amp;nbsp;Rajgir Wildlife Sanctuary,&amp;nbsp;Vikramshila Gangetic Dolphin Sanctuary&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Note: Recently Madhya Pradesh&amp;rsquo;s Panna National Park has been declared a UNESCO Biosphere Reserve&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;पश्चिम बंगाल&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;बक्सा बाघ अभयारण्य पश्चिम बंगाल में स्थित है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;बक्सा बाघ अभयारण्य &lt;strong&gt;1983 में स्थापित &lt;/strong&gt;किया गया था।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;भारत में&lt;/strong&gt; तत्कालीन &lt;strong&gt;15&lt;sup&gt;वां&lt;/sup&gt; बाघ अभयारण्य &lt;/strong&gt;था।&lt;/li&gt;
	&lt;li&gt;बक्सा बाघ अभयारण्य में पाए जाने वाले जानवर भारतीय तेंदुआ, बंगाल बाघ, क्लाउडेड तेंदुआ, विशाल गिलहरी, गौर, चीतल और जंगली सूअर हैं।&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;पश्चिम बंगाल में राष्ट्रीय उद्यान/वन्यजीव अभयारण्य &lt;strong&gt;पश्चिम सुंदरबन वन्यजीव अभयारण्य, गोरुमारा राष्ट्रीय उद्यान, नेओरा घाटी राष्ट्रीय उद्यान, सिंगालीला राष्ट्रीय उद्यान, सुंदरबन राष्ट्रीय उद्यान (एसटीआर) बाघ अभयारण्य&lt;/strong&gt;&lt;strong&gt;, और जलदाप राष्ट्रीय उद्यान&lt;/strong&gt; हैं।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;राज्य&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;राष्ट्रीय उद्यान/वन्यजीव अभयारण्य&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;झारखंड&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;सिंहभूम हाथी अभ्यारण्य, बेतला राष्ट्रीय उद्यान, दलमा वन्यजीव अभयारण्य, हजारीबाग वन्यजीव अभयारण्य&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;छत्तीसगढ&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;अचनकमार वन्यजीव अभयारण्य, इंद्रावती बाघ अभयारण्य, नामित जंगली भैंस वन्यजीव अभयारण्य, कांगेर घाटी राष्ट्रीय उद्यान, गुरु घासी दास (संजय) राष्ट्रीय उद्यान&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बिहार&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वाल्मीकि बाघ अभयारण्य, राजगीर वन्यजीव अभयारण्य, विक्रमशिला गंगात्मक डॉल्फिन अभयारण्य&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;टिप्पणी: हाल ही में मध्य प्रदेश के पन्ना राष्ट्रीय उद्यान को यूनेस्को बायोस्फीयर रिजर्व घोषित किया गया है।&lt;/strong&gt;&lt;/p&gt;
